-- ============================================
-- Legislacao full-site: confucio-moura / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2019-2025
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/475/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2019_2025_20260506
--
-- Filtro factual: endpoint senador/475/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=475
--   com NumOrdemAutor=1. Resultado deste snapshot: 95 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'confucio-moura';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'confucio-moura: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('136600', '138762', '139657', '135288', '135415', '135418', '135798', '136039', '136652', '136998', '137513', '137611', '137660', '137869', '138499', '138676', '138904', '138905', '139450', '139582', '139585', '140079', '135675', '140517', '141448', '141472', '141485', '141486', '141510', '141635', '141636', '141637', '141639', '141642', '141673', '141757', '141824', '141833', '141844', '141926', '141927', '141941', '142108', '142927', '143116', '143253', '143428', '143470', '143636', '143753', '143914', '143926', '144350', '144633', '144657', '145506', '145544', '146503', '146957', '147518', '151902', '151903', '153346', '154096', '155016', '155017', '155086', '156912', '157588', '158404', '159470', '159471', '159501', '161504', '162691', '162698', '163431', '163432', '165409', '165559', '169512', '169516', '169626', '169627', '169640', '169641', '169642', '169643', '169644', '170081', '170083', '170637', '170992', '171631', '169175');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('136600', '138762', '139657', '135288', '135415', '135418', '135798', '136039', '136652', '136998', '137513', '137611', '137660', '137869', '138499', '138676', '138904', '138905', '139450', '139582', '139585', '140079', '135675', '140517', '141448', '141472', '141485', '141486', '141510', '141635', '141636', '141637', '141639', '141642', '141673', '141757', '141824', '141833', '141844', '141926', '141927', '141941', '142108', '142927', '143116', '143253', '143428', '143470', '143636', '143753', '143914', '143926', '144350', '144633', '144657', '145506', '145544', '146503', '146957', '147518', '151902', '151903', '153346', '154096', '155016', '155017', '155086', '156912', '157588', '158404', '159470', '159471', '159501', '161504', '162691', '162698', '163431', '163432', '165409', '165559', '169512', '169516', '169626', '169627', '169640', '169641', '169642', '169643', '169644', '170081', '170083', '170637', '170992', '171631', '169175')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao confucio-moura: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'RO'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2025
    AND COALESCE(hp.periodo_fim, 9999) >= 2019;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao confucio-moura: mandato Senado/RO 2019-2025 nao encontrado em historico_politico';
  END IF;
END $$;

