    ('PL', '4524', 2020, 'Altera a Lei no 9.472, de 16 de julho de 1997, que dispõe sobre a organização dos serviços de telecomunicações, a criação e funcionamento de um órgão regulador e outros aspectos institucionais, nos termos da Emenda Constitucional nº 8, de 1995; a Lei nº 9.998, de 17 de agosto de 2000; e a Lei nº 13.116, de 20 de abril de 2015, para dispor sobre o Fundo de Universalização dos Serviços de Telecomunicações e estabelecer mecanismos para ampliar o acesso à internet e promover a inclusão digital.', 'Senado', '144633', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/144633', 'confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2025_20260506', '{"proposicao_id_api":"144633","descricao_identificacao":"PL 4524/2020","data_apresentacao":"2020-09-10","casa":"SF","codigo_parlamentar_senado":475,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"MDB","uf_autor_no_protocolo":"RO","autor_nome":"Confúcio Moura","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/475/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/144633.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/144633.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/144633","coverage_id":"confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2025_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"confucio-moura-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T04:01:35.045Z"}'::jsonb),
