    ('PL', '3484', 2025, 'Altera a Lei nº 9.294, de 15 de julho de 1996, que dispõe sobre as restrições ao uso e à propaganda de produtos fumígeros, bebidas alcoólicas, medicamentos, terapias e defensivos agrícolas, nos termos do § 4° do art. 220 da Constituição Federal, para vedar o uso de aditivos em produtos fumígenos e estabelecer padrão gráfico único nas embalagens desses produtos.', 'Senado', '169627', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/169627', 'confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2025_20260506', '{"proposicao_id_api":"169627","descricao_identificacao":"PL 3484/2025","data_apresentacao":"2025-07-16","casa":"SF","codigo_parlamentar_senado":475,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"MDB","uf_autor_no_protocolo":"RO","autor_nome":"Confúcio Moura","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/475/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/169627.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/169627.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/169627","coverage_id":"confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2025_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"confucio-moura-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T04:01:35.045Z"}'::jsonb),
