DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'confucio-moura';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'confucio-moura: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_confucio_moura_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'RO'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao confucio-moura: existem % anos de proposicoes Senado sem cobertura em mandato Senado/RO', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'confucio-moura'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_confucio_moura_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'confucio-moura';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'confucio-moura: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('136600', '138762', '139657', '135288', '135415', '135418', '135798', '136039', '136652', '136998', '137513', '137611', '137660', '137869', '138499', '138676', '138904', '138905', '139450', '139582', '139585', '140079', '135675', '140517', '141448', '141472', '141485', '141486', '141510', '141635', '141636', '141637', '141639', '141642', '141673', '141757', '141824', '141833', '141844', '141926', '141927', '141941', '142108', '142927', '143116', '143253', '143428', '143470', '143636', '143753', '143914', '143926', '144350', '144633', '144657', '145506', '145544', '146503', '146957', '147518', '151902', '151903', '153346', '154096', '155016', '155017', '155086', '156912', '157588', '158404', '159470', '159471', '159501', '161504', '162691', '162698', '163431', '163432', '165409', '165559', '169512', '169516', '169626', '169627', '169640', '169641', '169642', '169643', '169644', '170081', '170083', '170637', '170992', '171631', '169175');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'confucio-moura-senado-completo-autoria-substantiva-2019-2025-20260506'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2019_2025_20260506';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 95 THEN
    RAISE EXCEPTION 'Pos-apply confucio-moura: esperadas 95 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 95 THEN
    RAISE EXCEPTION 'Pos-apply confucio-moura: esperadas 95 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply confucio-moura: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply confucio-moura Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
